actions.script:
import org.moqui.util.RestClient
import ro.flexbiz.util.commons.StringUtils

int count = 0
List<String> errors = []

// Get all customers. We query by PartyRole to get unique partyIds safely.
def customerRoles = ec.entity.find("mantle.party.PartyRole")
        .condition("roleTypeId", "Customer")
        .list()

for (def customerRole in customerRoles) {
    String partyId = customerRole.partyId

    // Fetch name using the built-in PartyDetail view
    def partyDetail = ec.entity.find("mantle.party.PartyDetail")
            .condition("partyId", partyId)
            .one()

    String name = partyDetail?.organizationName ?: "${partyDetail?.nickname ?: ''}".trim()
    if (!name) name = "Customer ${partyId}"

    // Fetch phone number using the built-in PartyContactMechTelecomNumber view
    def telecomList = ec.entity.find("mantle.party.contact.PartyContactMechTelecomNumber")
            .condition("partyId", partyId)
            .condition("contactMechPurposeId", "PhonePrimary")
            .orderBy("-fromDate")
            .list()

    def telecom = telecomList ? telecomList.first() : null

    String phone = ""
    if (telecom) {
        phone = (telecom.countryCode ? '+' + telecom.countryCode + ' ' : '') +
                (telecom.areaCode ? telecom.areaCode + ' ' : '') +
                telecom.contactNumber
        phone = ro.flexbiz.util.commons.StringUtils.sanitizePhoneNumber(phone)
    }

    if (StringUtils.isEmpty(phone))
        continue

    // Build vCard 3.0 format simple string
        StringBuilder vcf = new StringBuilder()
    vcf.append("BEGIN:VCARD\nVERSION:3.0\n")
    vcf.append("FN:").append(name).append("\n")
    if (phone) {
        vcf.append("TEL;TYPE=CELL,VOICE:").append(phone).append("\n")
    }
    vcf.append("CATEGORIES:Clienti\n")
    vcf.append("UID:moqui_party_").append(partyId).append("\n")
    vcf.append("END:VCARD\n")

    // Assuming Nextcloud CardDAV URL path structure: /remote.php/dav/addressbooks/users/{username}/{addressbook}/
    String urlStr = "${nextcloudUrl}/remote.php/dav/addressbooks/users/${username}/${addressbookName}/moqui_party_${partyId}.vcf"

    RestClient restClient = ec.service.rest().method("PUT").uri(urlStr)
            .basicAuth(username, password)
            .text(vcf.toString())

    try {
        RestClient.RestResponse restResponse = restClient.call()
        if (restResponse.statusCode < 200 || restResponse.statusCode >= 300) {
            String errMsg = "Failed to sync party ${partyId} to Nextcloud: HTTP ${restResponse.statusCode} - ${restResponse.text()}"
            ec.logger.warn(errMsg)
            errors.add(errMsg)
        } else {
            count++
        }
    } catch (Exception e) {
        String errMsg = "Error syncing party ${partyId} to Nextcloud: ${e.message}"
        ec.logger.error(errMsg, e)
        errors.add(errMsg)
    }
}

String msg = "Successfully synced ${count} customers to Nextcloud address book '${addressbookName}'. ${errors.size()} errors."
ec.logger.info(msg)

response = [successCount: count, errorCount: errors.size(), message: msg, errors: errors]

